const abas = $input.first().json.sheets.map(s => s.properties.title);
return [{
  json: {
    aviso_para_a_ia: "Você não especificou o nome da aba. Aqui estão as abas disponíveis. Chame esta ferramenta novamente usando um destes nomes no parâmetro 'nome_do_separador'.",
    abas_disponiveis: abas
  }
}];

// Recebe o termo de pesquisa enviado pelo Agente de IA
const triggerData = $('Execute Workflow Trigger').first().json || {};
const termoBusca = (triggerData.termo_de_pesquisa || '').toLowerCase().trim();
const nomeAba = triggerData.nome_do_separador || triggerData.query || '';

const todasLinhas = $input.all();

// Palavras genéricas que a IA costuma inventar. Se ela mandar isso, ignoramos o filtro.
const termosGenericos = ['todos', 'todas', 'all', 'análise', 'analise', 'geral', 'relatório', 'relatorio', 'catalogo', 'catálogo'];

// Normaliza: minúsculo + remove acentos. Deixa a busca tolerante a acentuação.
function norm(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

// Distância de edição (Levenshtein) — usada para casar variações de 1 letra
// como 'lilika' (usuário) vs 'lilica' (planilha).
function lev(a, b) {
  const m = a.length, n = b.length;
  if (Math.abs(m - n) > 1) return 2; // só nos importa <= 1
  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[i][j] = Math.min(dp[i - 1][j] + 1, dp[i][j - 1] + 1, dp[i - 1][j - 1] + cost);
    }
  }
  return dp[m][n];
}

// Um termo casa uma linha se: (substring exata normalizada) OU
// (alguma palavra da linha com >=4 letras está a 1 edição do termo).
function termoCasaLinha(termo, linhaTextoNorm, palavrasLinha) {
  if (linhaTextoNorm.includes(termo)) return true;
  if (termo.length < 4) return false;
  for (const w of palavrasLinha) {
    if (w.length >= 4 && lev(termo, w) <= 1) return true;
  }
  return false;
}

// Helper: envelope padrão {ok,data,error}. Garante que o n8n NUNCA receba array vazio
// (que pararia a execução com 'No output data returned').
function envelope(ok, items, msg) {
  return [{
    json: {
      ok,
      aba: nomeAba,
      termo_pesquisado: termoBusca || null,
      total: items.length,
      linhas: items.map(i => i.json),
      mensagem: msg || null
    }
  }];
}

// Caso 1: planilha vazia ou aba inexistente
if (todasLinhas.length === 0) {
  return envelope(false, [], `Nenhuma linha encontrada na aba '${nomeAba}'. Confira o nome.`);
}

// Caso 2: sem termo ou termo genérico → amostra das últimas 150 linhas
if (!termoBusca || termosGenericos.includes(termoBusca)) {
  const amostra = todasLinhas.slice(-150);
  return envelope(true, amostra, 'Termo genérico ou vazio — devolvendo amostra.');
}

// Pré-computa texto normalizado e palavras de cada linha.
const linhasIndex = todasLinhas.map(item => {
  const texto = norm(JSON.stringify(item.json));
  return { item, texto, palavras: texto.split(/[^a-z0-9]+/).filter(Boolean) };
});

// Caso 3: filtro por termo (múltiplas palavras separadas por espaço — AND, com fuzzy)
const termos = norm(termoBusca).split(/\s+/).filter(Boolean);
let usouFuzzy = false;
const resultados = [];
for (const L of linhasIndex) {
  const casaTudo = termos.every(t => {
    const exato = L.texto.includes(t);
    if (exato) return true;
    if (t.length >= 4 && L.palavras.some(w => w.length >= 4 && lev(t, w) <= 1)) {
      usouFuzzy = true;
      return true;
    }
    return false;
  });
  if (casaTudo) resultados.push(L.item);
}

if (resultados.length > 0) {
  const msg = usouFuzzy
    ? `Busca aproximada (o termo '${termoBusca}' pode ter variação de grafia na planilha).`
    : null;
  return envelope(true, resultados.slice(0, 100), msg);
}

// Caso 4: AND não bateu — tenta OR (qualquer termo, exato ou fuzzy) como rede de segurança
const resultadosOr = [];
for (const L of linhasIndex) {
  const casaAlgum = termos.some(t => termoCasaLinha(t, L.texto, L.palavras));
  if (casaAlgum) resultadosOr.push(L.item);
}
if (resultadosOr.length > 0) {
  return envelope(true, resultadosOr.slice(0, 100), `Sem correspondência exata para '${termoBusca}'. Devolvendo aproximações por termo.`);
}

// Caso 5: nada bateu — envelope vazio mas VÁLIDO (não quebra o fluxo)
return envelope(true, [], `Nenhuma linha contém '${termoBusca}' na aba '${nomeAba}'. Tente outro termo (ex: marca sem o sufixo, ou nome do modelo) ou peça a amostra (termo vazio).`);
